={{
(() => {
  const a = $('Parse OpenAI Analysis').first().json;
  const lines = [];

  // SUMMARY
  lines.push('Summary:');
  lines.push(`- ${a.summary || 'No unusual activity detected.'}`);

  // DETAILS
  lines.push('');
  lines.push('Details:');

  // People
  lines.push(`- Person count: ${a.person_count ?? 0}`);

  for (const p of (a.people || [])) {
    const ageGender = [
      p.approximate_age_group,
      p.apparent_gender
    ].filter(Boolean).join(' ');

    if (ageGender) {
      lines.push(
        `- Approximate age group and gender: ${
          ageGender.charAt(0).toUpperCase() + ageGender.slice(1)
        }`
      );
    }

    if (p.clothing) {
      lines.push(`- Clothing description: ${p.clothing}`);
    }

    if (p.behavior) {
      let activity = p.behavior;
      activity = activity.charAt(0).toUpperCase() + activity.slice(1);
      lines.push(`- Activity: ${activity}`);
    } else if (a.activity) {
      let activity = a.activity.replaceAll('_', ' ');
      activity = activity.charAt(0).toUpperCase() + activity.slice(1);
      lines.push(`- Activity: ${activity}`);
    }

    if (p.direction_of_travel) {
      lines.push(`- Direction of travel: ${p.direction_of_travel}`);
    }

    if (p.items_held && p.items_held.length) {
      for (const item of p.items_held) {
        let held = item.description || item.likely_identification;
        if (held) {
          lines.push(`- Items held: ${held}`);
        }
      }
    } else if (p.hands_status) {
      lines.push(
        `- Hands: ${p.hands_status.replaceAll('_', ' ')}; no item clearly identified`
      );
    }
  }

  // Package
  if (a.package_present) {
    let pkg = `${a.package_size || 'Unknown size'} package`;
    if (a.package_location) pkg += `, ${a.package_location}`;
    lines.push(`- Package: ${pkg}`);

    if (a.package_activity) {
      lines.push(
        `- Package activity: ${a.package_activity.replaceAll('_', ' ')}`
      );
    }

    if (a.delivery_service) {
      lines.push(
        `- Delivery service: ${a.delivery_service}` +
        (a.delivery_service_confidence
          ? ` (${a.delivery_service_confidence})`
          : '')
      );
    }
  }

  // Vehicles
  if (a.vehicle_present) {
    if (a.vehicles?.length) {
      for (const v of a.vehicles) {
        if (typeof v === 'string') {
          lines.push(`- Vehicle: ${v}`);
        } else {
          const text =
            v.description ||
            v.type ||
            JSON.stringify(v);
          lines.push(`- Vehicle: ${text}`);
        }
      }
    } else {
      lines.push(`- Vehicles visible: ${a.vehicle_count || 1}`);
    }
  }

  // Animals
  if (a.animal_present) {
    if (a.animals?.length) {
      for (const animal of a.animals) {
        if (typeof animal === 'string') {
          lines.push(`- Animal: ${animal}`);
        } else {
          const text =
            animal.description ||
            animal.type ||
            JSON.stringify(animal);
          lines.push(`- Animal: ${text}`);
        }
      }
    } else {
      lines.push(`- Animals visible: ${a.animal_count || 1}`);
    }
  }

  // Compact negative statement like the original notification
  const absent = [];
  if (!a.package_present) absent.push('packages');
  if (!a.vehicle_present) absent.push('vehicles');
  if (!a.animal_present) absent.push('animals');

  if (absent.length) {
    let text;
    if (absent.length === 1) {
      text = absent[0];
    } else if (absent.length === 2) {
      text = `${absent[0]} or ${absent[1]}`;
    } else {
      text = `${absent[0]}, ${absent[1]}, or ${absent[2]}`;
    }
    lines.push(`- No ${text} visible`);
  }

  // Visible text / logos
  if (a.visible_text?.length) {
    const texts = a.visible_text.map(t =>
      typeof t === 'string'
        ? t
        : (t.text || t.description || JSON.stringify(t))
    );
    lines.push(`- Visible text: ${texts.join('; ')}`);
  }

  // Security flags
  if (a.potentially_dangerous_object_present) {
    lines.push('- WARNING: Potentially dangerous object visible');
  }

  if (a.unusual_or_suspicious) {
    lines.push(
      `- Suspicious/unusual behavior: ${
        a.unusual_or_suspicious_description || 'Observed'
      }`
    );
  } else {
    lines.push('- No suspicious behavior noted');
  }

  return lines.join('\n');
})()
}}

