const response = $input.first().json;

// Make sure OpenAI actually completed the response.
if (response.status !== 'completed') {
  throw new Error(
    `OpenAI response incomplete: ${response.incomplete_details?.reason || response.status}`
  );
}

// Extract the JSON text returned by the vision model.
const text = response.output?.[0]?.content?.[0]?.text;

if (!text) {
  throw new Error('No analysis text returned by OpenAI');
}

// Parse the structured JSON.
let analysis;

try {
  analysis = JSON.parse(text);
} catch (error) {
  throw new Error(`Invalid JSON returned by OpenAI: ${error.message}`);
}

// Return clean structured fields plus AI telemetry.
return [{
  json: {
    ...analysis,

    openai_model: response.model || null,
    input_tokens: response.usage?.input_tokens || 0,
    output_tokens: response.usage?.output_tokens || 0,
    total_tokens: response.usage?.total_tokens || 0,

    ai_response_id: response.id || null,

    // Preserve the complete original OpenAI response.
    ai_response: response
  }
}];

const merged = $input.first().json;
const ai = $('Parse OpenAI Analysis').first().json;
const frigate = $('Code in JavaScript').first().json;

// The original Frigate MQTT payload
const message = frigate.message;

// Serialize values destined for PostgreSQL JSONB columns.
// This prevents n8n/Postgres from interpreting JavaScript arrays
// as PostgreSQL text[] arrays.
const jsonb = (value, fallback = null) => {
  return JSON.stringify(value ?? fallback);
};

// Build one flat record whose property names exactly match PostgreSQL columns.
return [{
  json: {
    event_id: message?.after?.id ?? null,
    event_time: new Date().toISOString(),

    workflow_id: $workflow.id,
    workflow_name: $workflow.name,
    execution_id: $execution.id,
    execution_status: 'success',
    execution_started_at: new Date().toISOString(),
    execution_finished_at: null,
    processing_ms: 0,
    trigger_type: 'MQTT',
    error_message: null,

    camera: message?.after?.camera ?? null,
    object_type: message?.after?.data?.objects?.[0] ?? 'unknown',
    frigate_event_id: message?.after?.id ?? null,
    frigate_score: 0,

    // JSONB
    frigate_metadata: jsonb(message, {}),

    summary: ai.summary ?? null,
    description: ai.description ?? null,
    activity: ai.activity ?? null,
    person_count: ai.person_count ?? 0,

    // JSONB
    people: jsonb(ai.people, []),

    recognized_person: ai.recognized_person ?? null,

    package_present: ai.package_present ?? false,
    package_size: ai.package_size ?? null,
    package_location: ai.package_location ?? null,
    package_activity: ai.package_activity ?? null,
    delivery_service: ai.delivery_service ?? null,
    delivery_service_confidence:
      ai.delivery_service_confidence ?? null,

    vehicle_present: ai.vehicle_present ?? false,
    vehicle_count: ai.vehicle_count ?? 0,

    // JSONB
    vehicles: jsonb(ai.vehicles, []),

    animal_present: ai.animal_present ?? false,
    animal_count: ai.animal_count ?? 0,

    // JSONB
    animals: jsonb(ai.animals, []),

    // JSONB
    visible_text: jsonb(ai.visible_text, []),

    potentially_dangerous_object_present:
      ai.potentially_dangerous_object_present ?? false,

    unusual_or_suspicious:
      ai.unusual_or_suspicious ?? false,

    unusual_or_suspicious_description:
      ai.unusual_or_suspicious_description ?? null,

    notification_sent: true,
    notification_service: 'Telegram',
    notification_destination: 'HampsteadGroup',

    openai_model: ai.openai_model ?? null,
    input_tokens: ai.input_tokens ?? 0,
    output_tokens: ai.output_tokens ?? 0,
    total_tokens: ai.total_tokens ?? 0,
    estimated_cost: 0,
    ai_response_id: ai.ai_response_id ?? null,

    // JSONB
    ai_response: jsonb(ai.ai_response, {}),

    // JSONB
    metadata: jsonb({
      source: 'frigate',
      workflow: $workflow.name,
      workflow_id: $workflow.id,
      execution_id: $execution.id
    }, {})
  }
}];
